"use strict";(self.webpackChunkcpp_docs=self.webpackChunkcpp_docs||[]).push([["9636"],{5589(n,t,i){i.r(t),i.d(t,{metadata:()=>e,default:()=>s,frontMatter:()=>o,contentTitle:()=>r,toc:()=>u,assets:()=>a});var e=JSON.parse('{"id":"multithreading-concurentcy/kha-nang-hien-thi-cua-bo-nho-memory-visibility","title":"Kh\u1EA3 n\u0103ng hi\u1EC3n th\u1ECB c\u1EE7a b\u1ED9 nh\u1EDB ( Memory Visibility)","description":"\u{1F9FE} Content","source":"@site/docs/multithreading-concurentcy/13-kha-nang-hien-thi-cua-bo-nho-memory-visibility.md","sourceDirName":"multithreading-concurentcy","slug":"/multithreading-concurentcy/kha-nang-hien-thi-cua-bo-nho-memory-visibility","permalink":"/cpp-notes/docs/multithreading-concurentcy/kha-nang-hien-thi-cua-bo-nho-memory-visibility","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/multithreading-concurentcy/13-kha-nang-hien-thi-cua-bo-nho-memory-visibility.md","tags":[],"version":"current","sidebarPosition":13,"frontMatter":{"title":"Kh\u1EA3 n\u0103ng hi\u1EC3n th\u1ECB c\u1EE7a b\u1ED9 nh\u1EDB ( Memory Visibility)"},"sidebar":"tutorialSidebar","previous":{"title":"V\u1EA5n \u0111\u1EC1 hi\u1EC7u n\u0103ng (Overhead)","permalink":"/cpp-notes/docs/multithreading-concurentcy/van-de-hieu-nang-overhead"},"next":{"title":"Starvation (B\u1ECF \u0111\xf3i lu\u1ED3ng)","permalink":"/cpp-notes/docs/multithreading-concurentcy/starvation-bo-doi-luong"}}'),c=i(4848),h=i(8453);let o={title:"Kh\u1EA3 n\u0103ng hi\u1EC3n th\u1ECB c\u1EE7a b\u1ED9 nh\u1EDB ( Memory Visibility)"},r="13. Kh\u1EA3 n\u0103ng hi\u1EC3n th\u1ECB c\u1EE7a b\u1ED9 nh\u1EDB ( Memory Visibility)",a={},u=[{value:"\u{1F9FE} Content",id:"-content",level:2},{value:"\u{1F4DD} Note",id:"-note",level:2}];function l(n){let t={code:"code",h1:"h1",h2:"h2",header:"header",pre:"pre",...(0,h.R)(),...n.components};return(0,c.jsxs)(c.Fragment,{children:[(0,c.jsx)(t.header,{children:(0,c.jsx)(t.h1,{id:"13-kh\u1EA3-n\u0103ng-hi\u1EC3n-th\u1ECB-c\u1EE7a-b\u1ED9-nh\u1EDB--memory-visibility",children:"13. Kh\u1EA3 n\u0103ng hi\u1EC3n th\u1ECB c\u1EE7a b\u1ED9 nh\u1EDB ( Memory Visibility)"})}),"\n",(0,c.jsx)(t.h2,{id:"-content",children:"\u{1F9FE} Content"}),"\n",(0,c.jsx)(t.pre,{children:(0,c.jsx)(t.code,{className:"language-cpp",children:"T\u1EA1i sao lu\u1ED3ng n\xe0y kh th\u1EA5y thay \u0111\u1ED5i c\u1EE7a lu\u1ED3ng kia?\nTrong c\xe1c h\u1EC7 th\u1ED1ng hi\u1EC7n \u0111\u1EA1i t\u1ED1c \u0111\u1ED9 c\u1EE7a CPU cao h\u01A1n r\u1EA5t nhi\u1EC1u so v\u1EDBi RAM, \u0111\u1EC3 kh\xf4ng ph\u1EA3i ch\u1EDD RAM, m\u1ED7i core c\u1EE7a CPU \u0111\u1EC1u c\xf3 c\xe1c t\u1EA7ng b\u1ED9 nh\u1EDB \u0111\u1EC7m ri\xeang (L1, L2 cache)\n1. Khi lu\u1ED3ng A ch\u1EA1y tr\xean core 1, thay \u0111\u1ED5i bi\u1EBFn stop = true gi\xe1 tr\u1ECB n\xe0y th\u01B0\u1EDDng ch\u1EC9 \u0111\u01B0\u1EE3c c\u1EADp nh\u1EADt v\xe0o L1 cache ho\u1EB7c 1 b\u1EA3ng \u0111\u1EC7m ghi (write buffer).\n2. Core 1 s\u1EBD ch\u01B0a c\u1EADp nh\u1EADt ngay xu\u1ED1ng RAM, v\xec ghi xu\u1ED1ng RAM r\u1EA5t ch\u1EADm\n3. Lu\u1ED3ng B ch\u1EA1y tr\xean core 2 ki\u1EC3m tra bi\u1EBFn stop. N\xf3 s\u1EBD \u0111\u1ECDc t\u1EEB L1 cache c\u1EE7a ch\xednh n\xf3 ho\u1EB7c RAM. V\xec core 1 ch\u01B0a x\u1EA3 d\u1EEF li\u1EC7u xu\u1ED1ng RAM, n\xean stop = false.\nk\u1EBFt qu\u1EA3: lu\u1ED3ng B ch\u1EA1y m\xe3i m\xe3i, d\xf9 lu\u1ED3ng A \u0111\xe3 ra l\u1EC7nh d\u1EEBng\n\nSolution:\n1. Gom c\u1EE5m c\xe1c thao t\xe1c ghi (batching)\n\u0111\u1EEBng ghi v\xe0o bi\u1EBFn d\xf9ng chung (shared variable) qu\xe1 th\u01B0\u1EDDng xuy\xean\n- sai: m\u1ED7i l\u1EA7n v\xf2ng l\u1EB7p ch\u1EA1y, c\u1ED9ng d\u1ED3n v\xe0o 1 bi\u1EBFn to\xe0n c\u1EE5c std::atomic. vi\u1EC7c n\xe0y \xe9p CPU ph\u1EA3i x\u1EA3 cache li\xean t\u1EE5c g\xe2y ngh\u1EBDn bus b\u1ED9 nh\u1EDB.\n- \u0111\xfang: d\xf9ng 1 bi\u1EBFn c\u1EE5c b\u1ED9 local variable \u0111\u1EC3 t\xednh to\xe1n trong cache c\u1EE7a ri\xeang nh\xe2n \u0111\xf3, sau khi xong xu\xf4i m\u1EDBi ghi k\u1EBFt qu\u1EA3 cu\u1ED3i c\xf9ng v\xe0o bi\u1EBFn d\xf9ng chung 1 l\u1EA7n duy nh\u1EA5t.\n\n2. thi\u1EBFt k\u1EBF single-writer (ch\u1EC9 m\u1ED9t lu\u1ED3ng ghi)\nhi\u1EC7u n\u0103ng t\u1ED1t nh\u1EA5t \u0111\u1EA1t \u0111\u01B0\u1EE3c khi thi\u1EBFt k\u1EBF h\u1EC7 th\u1ED1ng sao cho\n- nhi\u1EC1u lu\u1ED3ng c\xf3 th\u1EC3 \u0111\u1ECDc (read-only) m\u1ED9t v\xf9ng nh\u1EDB\n- ch\u1EC9 uy nh\u1EA5t m\u1ED9t lu\u1ED3ng \u0111\u01B0\u1EE3c quy\u1EC1n ghi v\xe0o c\xf9ng nh\u1EDB \u0111\xf3. khi \u0111\xf3, c\xf3 th\u1EC3 d\xf9ng memory_order_relaxed ho\u1EB7c th\u1EADm ch\xed kh\xf4ng c\u1EA7n lock trong nhi\u1EC1u tr\u01B0\u1EDDng h\u1EE3p v\xec kh\xf4ng c\xf3 xung \u0111\u1ED9t khi ghi\n"})}),"\n",(0,c.jsx)(t.h2,{id:"-note",children:"\u{1F4DD} Note"})]})}function s(n={}){let{wrapper:t}={...(0,h.R)(),...n.components};return t?(0,c.jsx)(t,{...n,children:(0,c.jsx)(l,{...n})}):l(n)}},8453(n,t,i){i.d(t,{R:()=>o,x:()=>r});var e=i(6540);let c={},h=e.createContext(c);function o(n){let t=e.useContext(h);return e.useMemo(function(){return"function"==typeof n?n(t):{...t,...n}},[t,n])}function r(n){let t;return t=n.disableParentContext?"function"==typeof n.components?n.components(c):n.components||c:o(n.components),e.createElement(h.Provider,{value:t},n.children)}}}]);